    #[test]
    fn test_splits_on_h1_headings() {
        let source = "# Introduction\n\nSome intro text.\n\n# Features\n\nFeature list here.\n";
        let chunker = MarkdownChunker::new();
        let chunks = chunker.chunk(source, &meta()).unwrap();
        assert_eq!(chunks.len(), 2);
        assert!(chunks[0].content.contains("# Introduction"));
        assert!(chunks[1].content.contains("# Features"));
    }

    #[test]
    fn test_splits_on_mixed_heading_levels() {
        let source = "# Top\n\nIntro.\n\n## Section A\n\nContent A.\n\n## Section B\n\nContent B.\n";
        let chunker = MarkdownChunker::new();
        let chunks = chunker.chunk(source, &meta()).unwrap();
        assert!(chunks.len() >= 2, "expected at least 2 chunks, got {}", chunks.len());
    }

    #[test]
    fn test_no_headings_returns_single_chunk() {
        let source = "Just some plain text without any headings.\nAnother line.";
        let chunker = MarkdownChunker::new();
        let chunks = chunker.chunk(source, &meta()).unwrap();
        assert_eq!(chunks.len(), 1);
        assert_eq!(chunks[0].chunk_type, "text");
    }

